import React, { Component } from 'react';
import './App.css';
import Home from './Home';
import { BrowserRouter as Router, Route, Switch, Redirect } from 'react-router-dom';
import QueueList from './QueueList';
import QueueEdit from "./QueueEdit";
import LoginPage from './LoginPage';
import { globalStateContext } from './Context'

class App extends Component {
  componentDidUpdate(prevProps, prevState) {
    if (this.state.isLoggedIn !== prevState.isLoggedIn) {
      localStorage.setItem("isLoggedIn", this.state.isLoggedIn)
    }
  }

  constructor(props) {
    super(props);

    this.change = (isLoggenIn) => {
      this.setState(state => ({
        isLoggedIn:
          isLoggenIn
      }));
      console.log("CHANGE!!!");
      console.log(this.state.isLoggedIn)
      fetch("/check_login").then(response => response.json()).then(response => {
        console.log("fetched " + response.success)
      })
    };
    // localStorage.removeItem("isLoggedIn");
    const isLoggedIn = localStorage.getItem("isLoggedIn") === "true"
    this.state = {
      isLoggedIn: isLoggedIn,
      change: this.change 
    };

    // fetch("/check_login").then(response => response.json()).then(response => {
    //   console.log("fetched " + this.state.isLoggedIn + " " + response.success);
    //   this.state = {
    //     isLoggedIn: response.success && isLoggedIn,
    //     change: this.change
    //   }
    // })
  }

  render() {
    return (
      <globalStateContext.Provider value={this.state}>
        <Router>
          <Switch>
            <Route path='/EmptyQueue/queue' exact={true} render={() => {
               return <QueueList />
              }}/>
              <Route path='/' exact={true} component={Home}/>
              <Route path='/EmptyQueue/' exact={true} component={Home}/>
              <Route path='/EmptyQueue/queue/:id' render={() => (
                  <QueueEdit />
                )}/>
            <Route path='/EmptyQueue/perform_login' component={LoginPage}/>
            <Route path='/perform_logout' render={() => {
              // fetch ("/perform_logout", {method: "POST"}).then(response => response.body).then(response => {console.log(response);this.change(false);}).catch(e => console.log("jopa " + e));
              return <Redirect to="/"/>
            }}/>
          </Switch>
        </Router>
      </globalStateContext.Provider>
    )
  }
}

export default App;